#include <cstdio>
#include <cstdlib>
#include <omp.h>

#define INF 1000000000

const int N = 1024;

void floyd_warshall(int *dist, int n) {
    for (int k = 0; k < n; ++k) {
        #pragma omp target teams distribute parallel for collapse(2) map(tofrom: dist[0:n*n])
        for (int i = 0; i < n; ++i) {
            for (int j = 0; j < n; ++j) {
                int ik = dist[i * n + k];
                int kj = dist[k * n + j];
                int ij = dist[i * n + j];
                if (ik + kj < ij) {
                    dist[i * n + j] = ik + kj;
                }
            }
        }
    }
}

int main(int argc, char **argv) {
    int n = N;
    if (argc > 1) {
        n = atoi(argv[1]);
        if (n > N) n = N;
    }

    int *dist = (int *)malloc(n * n * sizeof(int));
    if (!dist) {
        fprintf(stderr, "Failed to allocate memory\n");
        return 1;
    }

    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < n; ++j) {
            dist[i * n + j] = (i == j) ? 0 : INF;
        }
    }

    for (int i = 0; i < n - 1; ++i) {
        dist[i * n + i + 1] = 1;
        dist[(i + 1) * n + i] = 1;
    }

    floyd_warshall(dist, n);

    for (int i = 0; i < (n < 10 ? n : 10); ++i) {
        for (int j = 0; j < (n < 10 ? n : 10); ++j) {
            if (dist[i * n + j] == INF)
                printf("INF ");
            else
                printf("%3d ", dist[i * n + j]);
        }
        printf("\n");
    }

    free(dist);
    return 0;
}
